import{_ as a,o as t,c as e,aQ as i}from"./chunks/framework.cDvftfeu.js";const u=JSON.parse('{"title":"Sports Facilities","description":"How to book sports facilities with Ham.","frontmatter":{"description":"How to book sports facilities with Ham."},"headers":[],"relativePath":"en/handbook/sport.md","filePath":"en/handbook/sport.md","lastUpdated":1777525243000}'),r={name:"en/handbook/sport.md"};function s(n,o,l,p,c,d){return t(),e("div",null,[...o[0]||(o[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /handbook/sport.md for this page in Markdown format</div><h1 id="sports-facilities" tabindex="-1">Sports Facilities <a class="header-anchor" href="#sports-facilities" aria-label="Permalink to &quot;Sports Facilities&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Version requirements</p><p>iOS: 1.3.2 (build &gt;= 96)</p><p>Android: 1.4.3</p></div><p>You can book sports facilities with Ham.</p><h2 id="preparation" tabindex="-1">Preparation <a class="header-anchor" href="#preparation" aria-label="Permalink to &quot;Preparation&quot;">​</a></h2><p>Before booking, log in to your information portal account in &quot;Me&quot; -&gt; &quot;Information Portal Settings.&quot;</p><h2 id="browse-facilities" tabindex="-1">Browse facilities <a class="header-anchor" href="#browse-facilities" aria-label="Permalink to &quot;Browse facilities&quot;">​</a></h2><p>When browsing facilities, you can select your sport and venue, then check available slots and times to book.</p><p>Browsing facilities is suitable when:</p><ul><li>You suddenly want to work out and have no booking</li><li>A venue has plenty of remaining slots</li></ul><h2 id="favorite-bookings" tabindex="-1">Favorite bookings <a class="header-anchor" href="#favorite-bookings" aria-label="Permalink to &quot;Favorite bookings&quot;">​</a></h2><p>You can set favorite venues, sessions, and time slots in settings. After you set them, the booking appears on the home page for quick booking.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>Quick booking on the home page does not confirm availability for the slot. If a booking fails, Ham will select a nearby available slot automatically.</p></div><h2 id="order-center" tabindex="-1">Order center <a class="header-anchor" href="#order-center" aria-label="Permalink to &quot;Order center&quot;">​</a></h2><p>On the home page, you can go to the order center to view or cancel your orders.</p><h2 id="pay-for-orders" tabindex="-1">Pay for orders <a class="header-anchor" href="#pay-for-orders" aria-label="Permalink to &quot;Pay for orders&quot;">​</a></h2><p>When a booking succeeds and payment is due, you can pay in two ways:</p><ul><li>Pay via WeChat mini program:</li></ul><p>Pay in the &quot;Venue Booking&quot; mini program. This option supports WeChat Pay.</p><ul><li>Pay on the web:</li></ul><p>After confirming the details, Ham provides a link to the university payment platform. Copy it to a browser to complete payment. This option supports Alipay or UnionPay.</p><div class="warning custom-block"><p class="custom-block-title">Important</p><p>Payments on the WHU payment platform are not handled by Ham.</p></div><h2 id="booking-status" tabindex="-1">Booking status <a class="header-anchor" href="#booking-status" aria-label="Permalink to &quot;Booking status&quot;">​</a></h2><p>Your booking status is shown on the home page.</p><p>When payment is due, you can pay from the booking status card.</p>',25)])])}const m=a(r,[["render",s]]);export{u as __pageData,m as default};
